import CreatePost from "../components/CreatePost";
import Feed from "../components/Feed";

const Home = () => {
  return (
    <div style={{ padding: "20px", maxWidth: "600px", margin: "auto" }}>
      <h2>Dashboard</h2>

      <CreatePost />
      <Feed />
    </div>
  );
};

export default Home;
